var registry = {"22cc744f-50f3-406a-883b-a9bf4cd71b0a":{"username":"partner.alpha","persona":"partner","partnerId":"partner-alpha","countries":"BR"},"partner.alpha":{"username":"partner.alpha","persona":"partner","partnerId":"partner-alpha","countries":"BR"},"05e366db-4ebc-4037-ae5a-6df50fa87ac8":{"username":"partner.beta","persona":"partner","partnerId":"partner-beta","countries":"MX"},"partner.beta":{"username":"partner.beta","persona":"partner","partnerId":"partner-beta","countries":"MX"},"962e7809-808a-4a8c-9abf-0d05f8ec235f":{"username":"telco.operations","persona":"operations","partnerId":"*","countries":"BR,MX,CO,AR,PE,CL"},"telco.operations":{"username":"telco.operations","persona":"operations","partnerId":"*","countries":"BR,MX,CO,AR,PE,CL"},"ba0403b6-8a9e-4c4c-95f4-934db8972deb":{"username":"telco.product","persona":"product_manager","partnerId":"*","countries":"BR,MX,CO,AR,PE,CL"},"telco.product":{"username":"telco.product","persona":"product_manager","partnerId":"*","countries":"BR,MX,CO,AR,PE,CL"},"693cdade-40cc-45b7-a56e-f9b013becd0e":{"username":"telco.admin","persona":"platform_administrator","partnerId":"*","countries":"*"},"telco.admin":{"username":"telco.admin","persona":"platform_administrator","partnerId":"*","countries":"*"},"admin":{"username":"admin","persona":"platform_administrator","partnerId":"*","countries":"*"}};
var jwt = String(
    mc.getProperty('backend.jwt') || ''
);

var subjectRaw = '';
var username = '';
var persona = '';
var partnerId = '';
var countries = '';
var claimKeys = '';

function decodeBase64Url(value) {
    var alphabet =
        'ABCDEFGHIJKLMNOPQRSTUVWXYZ' +
        'abcdefghijklmnopqrstuvwxyz' +
        '0123456789+/';

    var normalized = String(value || '')
        .replace(/-/g, '+')
        .replace(/_/g, '/');

    while (normalized.length % 4 !== 0) {
        normalized += '=';
    }

    var bytes = '';
    var buffer = 0;
    var bits = 0;

    for (
        var index = 0;
        index < normalized.length;
        index++
    ) {
        var character =
            normalized.charAt(index);

        if (character === '=') {
            break;
        }

        var alphabetIndex =
            alphabet.indexOf(character);

        if (alphabetIndex < 0) {
            continue;
        }

        buffer =
            (buffer << 6) |
            alphabetIndex;

        bits += 6;

        if (bits >= 8) {
            bits -= 8;

            bytes += String.fromCharCode(
                (buffer >> bits) & 255
            );
        }
    }

    try {
        var encoded = '';

        for (
            var byteIndex = 0;
            byteIndex < bytes.length;
            byteIndex++
        ) {
            var hex =
                bytes
                    .charCodeAt(byteIndex)
                    .toString(16);

            encoded +=
                '%' +
                (
                    hex.length === 1
                        ? '0' + hex
                        : hex
                );
        }

        return decodeURIComponent(encoded);
    } catch (ignored) {
        return bytes;
    }
}

function normalizeIdentity(value) {
    if (
        value === null ||
        typeof value === 'undefined'
    ) {
        return '';
    }

    var normalized = String(value)
        .replace(/^\s+|\s+$/g, '')
        .replace(/^"+|"+$/g, '')
        .replace(/@carbon\.super$/i, '')
        .replace(/^PRIMARY\//i, '')
        .replace(/^Internal\//i, '');

    if (
        normalized.indexOf('/') >= 0
    ) {
        var pieces =
            normalized.split('/');

        normalized =
            pieces[pieces.length - 1];
    }

    return normalized;
}

try {
    var token = jwt;

    if (
        token.indexOf('.') < 0 &&
        token.length > 0
    ) {
        var outerDecoded =
            decodeBase64Url(token);

        if (
            outerDecoded.indexOf('.') >= 0
        ) {
            token = outerDecoded;
        }
    }

    var tokenParts =
        token.split('.');

    if (tokenParts.length >= 2) {
        var claims = JSON.parse(
            decodeBase64Url(
                tokenParts[1]
            )
        );

        var keys = [];

        for (var key in claims) {
            if (
                Object.prototype
                    .hasOwnProperty
                    .call(claims, key)
            ) {
                keys.push(key);
            }
        }

        claimKeys = keys.join(',');

        var candidates = [
            claims[
                'http://wso2.org/claims/enduser'
            ],
            claims[
                'http://wso2.org/claims/username'
            ],
            claims.preferred_username,
            claims.username,
            claims.sub
        ];

        subjectRaw = String(
            candidates[0] ||
            candidates[candidates.length - 1] ||
            ''
        );

        for (
            var candidateIndex = 0;
            candidateIndex < candidates.length;
            candidateIndex++
        ) {
            var candidate =
                normalizeIdentity(
                    candidates[candidateIndex]
                );

            if (
                candidate &&
                registry[candidate]
            ) {
                var identity =
                    registry[candidate];

                username =
                    identity.username;

                persona =
                    identity.persona;

                partnerId =
                    identity.partnerId;

                countries =
                    identity.countries;

                break;
            }
        }
    }
} catch (error) {
    mc.setProperty(
        'backend.jwt.decode.error',
        String(error)
    );
}

mc.setProperty(
    'backend.jwt.subject.raw',
    subjectRaw
);

mc.setProperty(
    'backend.jwt.claim.keys',
    claimKeys
);

mc.setProperty(
    'authenticated.user',
    username
);

mc.setProperty(
    'persona',
    persona
);

mc.setProperty(
    'authorized.partner.id',
    partnerId
);

mc.setProperty(
    'authorized.countries',
    countries
);
